with open(BASE / 'story_events_output.json', 'r', encoding='utf-8') as f:
    part4b5 = json.load(f)

# Merge all story events
all_story_events = {}
all_story_events.update(PART1_2)
all_story_events.update(PART3A)
all_story_events.update(PART3B)
for k, v in part4a.items():
    all_story_events[k] = v.get('story_event', v)
for k, v in part4b5.items():
    if isinstance(v, dict) and 'story_event' in v:
        all_story_events[k] = v['story_event']
    elif isinstance(v, dict) and 'location' in v:
        all_story_events[k] = v

print(f"Total story_events collected: {len(all_story_events)}")

# Apply story_events and callbacks to lessons
story_count = 0
callback_count = 0
growth_count = 0

for lesson in lessons:
    lid = lesson['id']
    lt = lesson.get('type', 'lesson')

    if lt != 'recap':
        # Regular lesson: add story_event
        if lid in all_story_events:
            lesson['story_event'] = all_story_events[lid]
            story_count += 1
        else:
            print(f"  WARNING: No story_event for regular lesson {lid}")

        # Add callback if present
        if lid in CALLBACKS:
            lesson['callback'] = CALLBACKS[lid]
            callback_count += 1
    else:
        # Recap lesson: add character_growth
        if lid in CHARACTER_GROWTH:
            lesson['character_growth'] = CHARACTER_GROWTH[lid]
            growth_count += 1
        else:
            print(f"  WARNING: No character_growth for recap {lid}")

# Validate
regular_lessons = [l for l in lessons if l.get('type', 'lesson') != 'recap']
recap_lessons = [l for l in lessons if l.get('type', 'lesson') == 'recap']

missing_story = [l['id'] for l in regular_lessons if 'story_event' not in l]
missing_growth = [l['id'] for l in recap_lessons if 'character_growth' not in l]

if missing_story:
    print(f"\n  MISSING story_event for: {missing_story}")
if missing_growth:
    print(f"\n  MISSING character_growth for: {missing_growth}")

print(f"\nResults:")
print(f"  story_events added: {story_count}/{len(regular_lessons)}")
print(f"  callbacks added: {callback_count}")
print(f"  character_growth added: {growth_count}/{len(recap_lessons)}")

# Save
with open(LESSONS_PATH, 'w', encoding='utf-8') as f:
    json.dump(lessons, f, ensure_ascii=False, indent=2)

print(f"\nSaved to {LESSONS_PATH}")
print("Done!")
